/*
  Course: INT-499 Capstone in Information Technology
  Instructor: John Russel
  Joshua Coman
*/


// App.js
import React, { useState, useEffect } from "react";
import { FaEdit, FaTrash, FaCheck } from "react-icons/fa";
import { Navbar } from "./Navbar";

export default function App() {
  const [items, setItems] = useState(() => {
    const saved = localStorage.getItem("streamlist-items");
    return saved ? JSON.parse(saved) : [];
  });
  const [input, setInput] = useState("");

  useEffect(() => {
    localStorage.setItem("streamlist-items", JSON.stringify(items));
  }, [items]);

  const addItem = () => {
    if (input.trim() === "") return;
    setItems([...items, { text: input, completed: false }]);
    setInput("");
  };

  const deleteItem = (index) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const toggleComplete = (index) => {
    const updated = [...items];
    updated[index].completed = !updated[index].completed;
    setItems(updated);
  };

  const editItem = (index, newText) => {
    const updated = [...items];
    updated[index].text = newText;
    setItems(updated);
  };

  return (
    <div className="min-h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-white">
      <Navbar />
      <div className="max-w-xl mx-auto p-4">
        <h1 className="text-2xl font-bold mb-4">StreamList</h1>
        <div className="flex mb-4">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Enter new item..."
            className="flex-1 p-2 border rounded-l"
          />
          <button
            onClick={addItem}
            className="bg-blue-600 text-white px-4 rounded-r"
          >
            Add
          </button>
        </div>

        <ul>
          {items.map((item, index) => (
            <li
              key={index}
              className="flex justify-between items-center p-2 mb-2 border rounded bg-white dark:bg-gray-800"
            >
              <span
                className={item.completed ? "line-through opacity-60" : ""}
              >
                {item.text}
              </span>
              <div className="flex gap-2">
                <button
                  onClick={() => {
                    const newText = prompt("Edit item:", item.text);
                    if (newText) editItem(index, newText);
                  }}
                  className="text-yellow-500"
                >
                  <FaEdit />
                </button>
                <button
                  onClick={() => toggleComplete(index)}
                  className="text-green-500"
                >
                  <FaCheck />
                </button>
                <button
                  onClick={() => deleteItem(index)}
                  className="text-red-500"
                >
                  <FaTrash />
                </button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
